import { useState } from 'react';

function TransactionForm({ addTransaction }) {
  const [description, setDescription] = useState('');
  const [amount, setAmount]           = useState('');
  const [type, setType]               = useState('income');
  const [category, setCategory]       = useState('');

  function handleSubmit(e) {
    e.preventDefault();

    if (!description || !amount || !category) return alert('Sabhi fields bharo!');
    if (isNaN(amount) || Number(amount) <= 0)  return alert('Valid amount daalo!');

    addTransaction({
      id: Date.now(),
      description,
      amount: Number(amount),
      type,
      category,
    });

    setDescription(''); setAmount(''); setCategory(''); setType('income');
  }

  return (
    <form onSubmit={handleSubmit}>
      <h2>Add Transaction</h2>
      <input
        placeholder="Description"
        value={description}
        onChange={e => setDescription(e.target.value)}
      />
      <input
        placeholder="Amount"
        type="number"
        value={amount}
        onChange={e => setAmount(e.target.value)}
      />
      <input
        placeholder="Category (e.g. Food, Job)"
        value={category}
        onChange={e => setCategory(e.target.value)}
      />
      <select value={type} onChange={e => setType(e.target.value)}>
        <option value="income">Income</option>
        <option value="expense">Expense</option>
      </select>
      <button type="submit">Add Transaction</button>
    </form>
  );
}

export default TransactionForm;